  def initialize(size)
    @parent = Array.new(size) { |i| i }
    @rank = Array.new(size, 1)
  end

  def find(x)
    if @parent[x] != x
      @parent[x] = find(@parent[x])
    end
    @parent[x]
  end

  def union(x, y)
    root_x = find(x)
    root_y = find(y)
    return false if root_x == root_y

    if @rank[root_x] > @rank[root_y]
      @parent[root_y] = root_x
      @rank[root_x] += @rank[root_y]
    else
      @parent[root_x] = root_y
      @rank[root_y] += @rank[root_x]
    end
    true
  end

  def count_components
    roots = Set.new
    @parent.each_index { |i| roots.add(find(i)) }
    roots.size
  end
end

def solve(n, edges, k)
  edges.sort_by! { |edge| edge[2] }
  left = 0
  right = edges.empty? ? 0 : edges.last[2]
  answer = 0

  while left <= right
    mid = (left + right) / 2
    uf = UnionFind.new(n)
    edges.each do |u, v, time|
      uf.union(u, v) if time > mid
    end
    components = uf.count_components

    if components >= k
      answer = mid
      right = mid - 1
    else
      left = mid + 1
    end
  end

